const h=$input.item.json.headers||{};
const body=$input.item.json.body||{};
const token=h['x-google-token'];
const account=(h['x-google-account']||'').replace(/-/g,'');
const devToken=$env.GOOGLE_ADS_DEV_TOKEN;
const action=(body.action||'').toLowerCase();
if(!token||!account)return[{json:{error:'Missing Google credentials'}}];
if(!devToken)return[{json:{error:'GOOGLE_ADS_DEV_TOKEN env var not set in n8n'}}];
const gHdr={'Authorization':`Bearer ${token}`,'developer-token':devToken,'Content-Type':'application/json'};
const GADS=`https://googleads.googleapis.com/v17/customers/${account}`;
let result;

if(action==='overview'){
  const r=await fetch(`${GADS}/googleAds:search`,{
    method:'POST',headers:gHdr,
    body:JSON.stringify({query:"SELECT metrics.cost_micros, metrics.conversions, metrics.conversions_value, metrics.clicks, metrics.impressions FROM campaign WHERE segments.date DURING LAST_30_DAYS AND campaign.status != 'REMOVED'"})
  });
  const results=(await r.json()).results||[];
  let costMicros=0,conversions=0,conversionsValue=0,clicks=0,impressions=0;
  for(const row of results){
    const m=row.metrics||{};
    costMicros+=parseInt(m.costMicros||0);
    conversions+=parseFloat(m.conversions||0);
    conversionsValue+=parseFloat(m.conversionsValue||0);
    clicks+=parseInt(m.clicks||0);
    impressions+=parseInt(m.impressions||0);
  }
  const totalSpend=costMicros/1000000;
  result={
    roas:totalSpend>0?Math.round((conversionsValue/totalSpend)*100)/100:0,
    total_spend:Math.round(totalSpend*100)/100,
    total_conversions:Math.round(conversions),
    total_clicks:clicks,
    total_impressions:impressions,
    platform:'google'
  };

}else if(action==='campaigns'){
  const r=await fetch(`${GADS}/googleAds:search`,{
    method:'POST',headers:gHdr,
    body:JSON.stringify({query:"SELECT campaign.id, campaign.name, campaign.status, campaign.advertising_channel_type, campaign_budget.amount_micros, campaign_budget.resource_name, metrics.cost_micros, metrics.conversions, metrics.conversions_value, metrics.clicks, metrics.impressions FROM campaign WHERE segments.date DURING LAST_30_DAYS AND campaign.status != 'REMOVED' ORDER BY metrics.cost_micros DESC LIMIT 50"})
  });
  const TYPE_MAP={SEARCH:'Search',DISPLAY:'Display',SHOPPING:'Shopping',VIDEO:'YouTube',PERFORMANCE_MAX:'PMAX',SMART:'Smart'};
  result=((await r.json()).results||[]).map(row=>{
    const c=row.campaign||{},b=row.campaignBudget||{},m=row.metrics||{};
    const costMicros=parseInt(m.costMicros||0);
    const convValue=parseFloat(m.conversionsValue||0);
    const spend=costMicros/1000000;
    const roas=spend>0?Math.round((convValue/spend)*100)/100:null;
    const statusRaw=c.status||'';
    const status=statusRaw==='ENABLED'?'live':statusRaw==='PAUSED'?'paused':'draft';
    const channelType=c.advertisingChannelType||'';
    const budgetMicros=parseInt(b.amountMicros||0);
    return{
      id:c.id,
      name:`Google · ${TYPE_MAP[channelType]||channelType}${c.name?' · '+c.name:''}`,
      status,platform:'google',channel_type:channelType,
      daily_budget:budgetMicros>0?budgetMicros/1000000:null,
      budget_resource:b.resourceName||null,
      roas,total_spend:Math.round(spend*100)/100,
      impressions:parseInt(m.impressions||0),
      clicks:parseInt(m.clicks||0),
      conversions:Math.round(parseFloat(m.conversions||0))
    };
  });

}else if(action==='toggle'){
  const campaignId=String(body.campaign_id||'');
  const status=body.status;
  if(!campaignId)return[{json:{success:false,error:'Missing campaign_id'}}];
  if(!['ENABLED','PAUSED'].includes(status))return[{json:{success:false,error:'status must be ENABLED or PAUSED'}}];
  const r=await fetch(`${GADS}/campaigns:mutate`,{
    method:'POST',headers:gHdr,
    body:JSON.stringify({operations:[{update:{resourceName:`customers/${account}/campaigns/${campaignId}`,status},updateMask:'status'}]})
  });
  const d=await r.json();
  result=d.partialFailureError?{success:false,error:d.partialFailureError.message}:{ok:true,campaign_id:campaignId,status};

}else{
  result={error:`Unknown action: ${action}`};
}

return[{json:result}];
